import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";


const FAQS = [
  { q: "What is a roofing square?", a: "A roofing square equals 100 square feet of roof area. It's the standard unit for ordering roofing materials. A 2,000 sq ft roof = 20 squares. When you add your waste percentage, you need extra squares for cuts and overlaps. Always order at least 10% more than your calculated squares." },
  { q: "How much waste should I factor in?", a: "Use 10-15% for a simple gable roof with no dormers or skylights. Use 15-20% for complex roofs with hips, valleys, dormers, or multiple peaks. Use 20-25% for roofs with many angles or skylight cutouts. Waste accounts for edge cuts, overlaps, and damaged/imperfect shingles." },
  { q: "How does roof pitch affect the area?", a: "Roof pitch is expressed as rise/run (e.g., 6/12 = 6 inches rise per 12 inches horizontal). Steeper pitches have more actual surface area than the footprint. The pitch factor formula is: - + (pitch/12)- A 6/12 pitch has a factor of ~1.118 - a 2,000 sq ft footprint becomes ~2,236 sq ft of actual roof area." },
  { q: "How many shingles do I need per square?", a: "Standard 3-tab shingles: 3 bundles per square (100 sq ft). Architectural/dimensional shingles: typically 3-4 bundles per square (check manufacturer specs). Metal roofing panels vary by profile. Always verify with your specific product's coverage data before ordering." },
  { q: "What is the pitch factor and how is it calculated?", a: "Pitch factor = - + (rise/run)- This is the trigonometric slope factor that converts horizontal footprint area to actual sloped roof area. Example: 4/12 pitch - - + (4/12)- = - + 0.111) = - - 1.054. A 1,500 sq ft footprint becomes 1,581 sq ft of roof surface." },
  { q: "What roofing materials are sold by the square?", a: "Sold by the square: asphalt shingles (3-tab and architectural), wood shingles and shakes, slate tiles, concrete tiles, clay tiles. Metal roofing is typically sold by the linear foot or panel. Underlayment and ice-and-water shield are sold by the roll (usually covering 4 squares per roll)." },
  { q: "How do I measure a complex roof?", a: "Break the roof into simple rectangles, triangles, and trapezoids. Calculate each section separately: rectangles = L  x  W, triangles = -  x  base  x  height. Apply the pitch factor to each section. Sum all sections and add your waste percentage. For very complex roofs, a professional measurement or drone survey is recommended." },
  { q: "What is the average cost to replace a roof?", a: "US average: $5,000-$12,000 for a typical 1,500-2,000 sq ft home with asphalt shingles. Material costs: 3-tab shingles ~$75-100/square, architectural shingles ~$100-150/square. Labor typically runs $50-$80/square for shingle installation. Metal, tile, and slate roofing cost significantly more - $200-$600+ per square installed." },
];

const PITCH_REFERENCE = [
  ["1/12", "1.004", "Barely visible slope", "Flat roofing required"],
  ["2/12", "1.014", "Very low slope", "Modified bitumen or TPO"],
  ["3/12", "1.031", "Low slope", "Min for asphalt shingles"],
  ["4/12", "1.054", "Moderate slope", "Common residential"],
  ["6/12", "1.118", "Steep (26.6 deg)", "Very common residential"],
  ["8/12", "1.202", "Very steep (33.7 deg)", "Cape Cod style"],
  ["10/12", "1.302", "Extremely steep (39.8 deg)", "Difficult installation"],
  ["12/12", "1.414", "45 deg angle", "Decorative/historic"],
];

export default function RoofingCalculator() {
  useCurrencyVersion();
  const [length, setLength] = useState(50);
  const [width, setWidth] = useState(30);
  const [pitch, setPitch] = useState(6);
  const [waste, setWaste] = useState(15);

  const footprint = length * width;
  const pitchFactor = Math.sqrt(1 + (pitch / 12) ** 2);
  const actualArea = footprint * pitchFactor;
  const withWaste = actualArea * (1 + waste / 100);
  const squares = withWaste / 100;
  const bundles = Math.ceil(squares * 3);
  const costEstLow = squares * 500;
  const costEstHigh = squares * 900;

  return (
    <>
      <SEOHead
        title="Free Roofing Calculator Online - Calculate Roof Area and Shingles Needed Instantly | CalcHive"
        description="Free online roofing calculator. Calculate roof area in squares, account for pitch and waste and estimate shingles needed instantly. 100% free for contractors and homeowners, no signup required."
        canonical="/roofing-calculator"
        keywords="free roofing calculator, roof area calculator free online, shingles calculator free, roofing squares calculator free, calculate roof pitch and area free"
        category="Construction Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-stone-600 dark:text-stone-400 bg-stone-100 dark:bg-stone-800/50 px-3 py-1 rounded-full mb-4 inline-block">Housing</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Roofing Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free roofing calculator to estimate roof area, squares, pitch impact, waste, and shingles needed. This roof area calculator free online also works as a shingles calculator free, roofing squares calculator free, and calculate roof pitch and area free tool.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="length" label="Building Length (ft)" value={length} min={10} max={200} step={1} onChange={setLength} format={v => `${v} ft`} testId="input-length" />
            <SliderInput id="width" label="Building Width (ft)" value={width} min={10} max={200} step={1} onChange={setWidth} format={v => `${v} ft`} testId="input-width" />
            <SliderInput id="pitch" label="Roof Pitch (rise per 12 inches)" value={pitch} min={1} max={12} step={1} onChange={setPitch} format={v => `${v}/12 (pitch factor: ${Math.sqrt(1 + (v/12)**2).toFixed(3)})`} testId="input-pitch" />
            <SliderInput id="waste" label="Waste Factor" value={waste} min={5} max={25} step={1} onChange={setWaste} format={v => `${v}%`} testId="input-waste" helpText="Simple gable: 10-15% - Complex hip/valley: 15-25%" />
          </div>
          <motion.div key={`${length}-${width}-${pitch}-${waste}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-stone-600 to-stone-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Roofing Squares Needed</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-squares">{squares.toFixed(1)}</p>
              <p className="text-white/70 text-sm mt-1">squares (including {waste}% waste)</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Roof Footprint", value: `${footprint.toLocaleString()} sq ft` },
                { label: "Actual Roof Area", value: `${Math.round(actualArea).toLocaleString()} sq ft` },
                { label: "Bundles (3-tab)", value: `${bundles} bundles` },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-sm font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
            <p className="text-xs text-muted-foreground mt-3 text-center">Estimated installed cost: ~{formatCurrencyValue(costEstLow, { maximumFractionDigits: 0 })}-{formatCurrencyValue(costEstHigh, { maximumFractionDigits: 0 })} (asphalt shingles, materials + labor)</p>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Roof Area and Squares for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Roof area is always larger than the building footprint because the roof is sloped. The pitch factor converts footprint area to actual surface area. Adding the waste percentage accounts for cuts at edges, valleys, and around obstructions.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Pitch Factor = sqrt(1 + (rise / 12)^2)</p>
            <p>Roof Area = Footprint  x  Pitch Factor</p>
            <p>Area with Waste = Roof Area  x  (1 + waste%)</p>
            <p>Squares = Area with Waste / 100</p>
            <p>Bundles (3-tab) = Squares  x  3</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Estimate Shingles Needed Including Waste</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Pitch", "Pitch Factor", "Slope Type", "Common Use"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {PITCH_REFERENCE.map(([p, factor, type, use]) => (
                  <tr key={p} className={`hover:bg-muted/30 ${p === `${pitch}/12` ? "bg-stone-50 dark:bg-stone-800/30 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-stone-600 dark:text-stone-400">{p}</td>
                    <td className="py-2.5 px-4 font-mono text-foreground">{factor}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{type}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{use}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Roof Material Calculator for Contractors and Homeowners</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Material", "Coverage per Unit", "Bundles per Square", "Approx. Cost"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["3-tab asphalt shingles", "33.3 sq ft per bundle", "3 bundles", "$75-100/square"],
                  ["Architectural shingles", "25-33 sq ft per bundle", "3-4 bundles", "$100-150/square"],
                  ["Metal roofing panels", "Varies by profile", "N/A", "$200-400/square"],
                  ["Slate tiles", "100 sq ft per square", "Varies", "$400-600/square"],
                  ["Clay/concrete tiles", "100 sq ft per square", "Varies", "$300-500/square"],
                  ["Wood shakes", "100 sq ft per square", "4 bundles", "$150-250/square"],
                ].map(([mat, cov, bundles_, cost]) => (
                  <tr key={mat} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{mat}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cov}</td>
                    <td className="py-2.5 px-4 text-stone-600 dark:text-stone-400">{bundles_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cost}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/roofing-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


